import React, { createContext, useState, useContext, useEffect } from "react";

const CurrencyContext = createContext();

export const CurrencyProvider = ({ children }) => {
  const [currency, setCurrency] = useState("₦"); // default Naira
  const [currencyCode, setCurrencyCode] = useState("NGN");

  // optional: auto-detect user location currency
  useEffect(() => {
    // Example: you can fetch location & set currency accordingly
  }, []);

  const changeCurrency = (symbol, code) => {
    setCurrency(symbol);
    setCurrencyCode(code);
  };

  return (
    <CurrencyContext.Provider value={{ currency, currencyCode, changeCurrency }}>
      {children}
    </CurrencyContext.Provider>
  );
};

export const useCurrency = () => useContext(CurrencyContext);
